parts.content:
apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location = /healthz {
            return 200 "ok\n";
            access_log off;
        }
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: flux-system
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default

parts.args:
{"title":"fix: Update vigil-app deployment image from nginx:declared-missing to nginx:stable","body":"Root cause: Deployment vigil-app manifest declares non-existent image tag nginx:declared-missing, causing ImagePullBackOff in newly scheduled pods

Evidence: Pod vigil-app-67cd9d8bb8-jk2w4 events: "Failed to pull image 'nginx:live-missing': rpc error: code = NotFound desc = failed to pull and unpack image 'docker.io/library/nginx:live-missing': docker.io/library/nginx:live-missing: not found"

The fix changes the image tag from nginx:declared-missing to nginx:stable to resolve the ImagePullBackOff errors."}

